#!/bin/sh
set -eu

export ABBY_RUNTIME_WALLET_API_BASE_URL="${ABBY_RUNTIME_WALLET_API_BASE_URL:-${VITE_WALLET_API_BASE_URL:-same-origin}}"
export ABBY_RUNTIME_WALLET_ID="${ABBY_RUNTIME_WALLET_ID:-}"
export ABBY_RUNTIME_ACTOR_DID="${ABBY_RUNTIME_ACTOR_DID:-}"
export ABBY_RUNTIME_ISSUER_KEY_HEX="${ABBY_RUNTIME_ISSUER_KEY_HEX:-}"
export ABBY_RUNTIME_AUDIENCE_KEY_HEX="${ABBY_RUNTIME_AUDIENCE_KEY_HEX:-}"
export ABBY_RUNTIME_FILECOIN_UPLOAD_URL="${ABBY_RUNTIME_FILECOIN_UPLOAD_URL:-}"
export ABBY_RUNTIME_FILECOIN_CLIENT_TOKEN="${ABBY_RUNTIME_FILECOIN_CLIENT_TOKEN:-}"
export ABBY_RUNTIME_VOICE_PROXY_ENABLED="${ABBY_RUNTIME_VOICE_PROXY_ENABLED:-${VITE_VOICE_PROXY_ENABLED:-}}"
export ABBY_RUNTIME_VOICE_PROXY_MODEL="${ABBY_RUNTIME_VOICE_PROXY_MODEL:-${VITE_VOICE_PROXY_MODEL:-}}"
export ABBY_RUNTIME_VOICE_PROXY_BASE_URL="${ABBY_RUNTIME_VOICE_PROXY_BASE_URL:-${IPFS_DATASETS_VOICE_PROXY_BASE_URL:-${VITE_VOICE_PROXY_BASE_URL:-}}}"
export ABBY_RUNTIME_VOICE_PROXY_INFER_URL="${ABBY_RUNTIME_VOICE_PROXY_INFER_URL:-${IPFS_DATASETS_VOICE_PROXY_INFER_URL:-${VITE_VOICE_PROXY_INFER_URL:-}}}"
export ABBY_RUNTIME_VOICE_PROXY_TTS_URL="${ABBY_RUNTIME_VOICE_PROXY_TTS_URL:-${IPFS_DATASETS_VOICE_PROXY_TTS_URL:-${VITE_VOICE_PROXY_TTS_URL:-}}}"
export ABBY_RUNTIME_VOICE_PROXY_STT_URL="${ABBY_RUNTIME_VOICE_PROXY_STT_URL:-${IPFS_DATASETS_VOICE_PROXY_STT_URL:-${VITE_VOICE_PROXY_STT_URL:-}}}"
export ABBY_RUNTIME_VOICE_PROXY_FALLBACK_INFER_URL="${ABBY_RUNTIME_VOICE_PROXY_FALLBACK_INFER_URL:-${IPFS_DATASETS_VOICE_PROXY_INFER_URL:-${VITE_VOICE_PROXY_FALLBACK_INFER_URL:-}}}"
export ABBY_RUNTIME_VOICE_PROXY_FALLBACK_TTS_URL="${ABBY_RUNTIME_VOICE_PROXY_FALLBACK_TTS_URL:-${IPFS_DATASETS_VOICE_PROXY_TTS_URL:-${VITE_VOICE_PROXY_FALLBACK_TTS_URL:-}}}"
export ABBY_RUNTIME_VOICE_PROXY_FALLBACK_STT_URL="${ABBY_RUNTIME_VOICE_PROXY_FALLBACK_STT_URL:-${IPFS_DATASETS_VOICE_PROXY_STT_URL:-${VITE_VOICE_PROXY_FALLBACK_STT_URL:-}}}"
export ABBY_RUNTIME_VOICE_PROXY_FALLBACK_MODEL="${ABBY_RUNTIME_VOICE_PROXY_FALLBACK_MODEL:-${VITE_VOICE_PROXY_FALLBACK_MODEL:-LiquidAI/LFM2.5-Audio-1.5B-proxy}}"

envsubst \
  '${ABBY_RUNTIME_WALLET_API_BASE_URL} ${ABBY_RUNTIME_WALLET_ID} ${ABBY_RUNTIME_ACTOR_DID} ${ABBY_RUNTIME_ISSUER_KEY_HEX} ${ABBY_RUNTIME_AUDIENCE_KEY_HEX} ${ABBY_RUNTIME_FILECOIN_UPLOAD_URL} ${ABBY_RUNTIME_FILECOIN_CLIENT_TOKEN} ${ABBY_RUNTIME_VOICE_PROXY_ENABLED} ${ABBY_RUNTIME_VOICE_PROXY_MODEL} ${ABBY_RUNTIME_VOICE_PROXY_BASE_URL} ${ABBY_RUNTIME_VOICE_PROXY_INFER_URL} ${ABBY_RUNTIME_VOICE_PROXY_TTS_URL} ${ABBY_RUNTIME_VOICE_PROXY_STT_URL} ${ABBY_RUNTIME_VOICE_PROXY_FALLBACK_INFER_URL} ${ABBY_RUNTIME_VOICE_PROXY_FALLBACK_TTS_URL} ${ABBY_RUNTIME_VOICE_PROXY_FALLBACK_STT_URL} ${ABBY_RUNTIME_VOICE_PROXY_FALLBACK_MODEL}' \
  < /opt/abby/runtime-config.template.json \
  > /usr/share/nginx/html/runtime-config.json
